import{_ as t,o as r,c as o,a3 as i}from"./chunks/framework.LBeL10WQ.js";const g=JSON.parse('{"title":"Distributor Score","description":"","frontmatter":{"title":"Distributor Score"},"headers":[],"relativePath":"en/publishers/score-distributor.md","filePath":"en/publishers/score-distributor.md"}'),a={name:"en/publishers/score-distributor.md"};function s(n,e,d,c,l,u){return r(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="distributor-score" tabindex="-1">Distributor Score <a class="header-anchor" href="#distributor-score" aria-label="Permalink to &quot;Distributor Score&quot;">​</a></h1><p>Your Distributor Score determines your visibility to advertisers — and therefore the volume of campaigns you receive. Understand it to maximize your revenue.</p><h2 id="what-is-the-distributor-score" tabindex="-1">What is the Distributor Score? <a class="header-anchor" href="#what-is-the-distributor-score" aria-label="Permalink to &quot;What is the Distributor Score?&quot;">​</a></h2><p>The Distributor Score is a <strong>5-star rating</strong> that evaluates the quality and reliability of your profile on the getinside platform.</p><p>It is recalculated <strong>dynamically</strong> in real-time and <strong>determines your ranking in the search engine</strong> that advertisers use to choose their distributors.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>High score = more visibility = more campaign proposals = more revenue.</p></div><h2 id="impact-based-on-your-score" tabindex="-1">Impact based on your score <a class="header-anchor" href="#impact-based-on-your-score" aria-label="Permalink to &quot;Impact based on your score&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card" style="border-color:var(--gi-tint-red-text);background:var(--gi-tint-red-bg);"><strong style="color:var(--gi-tint-red-text);">⭐⭐ Less than 3/5</strong><p style="margin:0.5rem 0 0;font-size:0.875rem;"><strong>Low visibility</strong> audience. Risk of no longer receiving campaign proposals.</p><p style="margin:0.5rem 0 0;font-size:0.8rem;color:var(--gi-tint-red-text);font-weight:600;">Immediate action required.</p></div><div class="gi-value-card"><strong>⭐⭐⭐ From 3 to 4/5</strong><p style="margin:0.5rem 0 0;font-size:0.875rem;"><strong>Standard</strong> visibility. You receive offers regularly.</p><p style="margin:0.5rem 0 0;font-size:0.8rem;color:var(--vp-c-text-2);">Decent profile — improvements are possible.</p></div><div class="gi-value-card" style="border-color:var(--gi-tint-green-text);background:var(--gi-tint-green-bg);"><strong style="color:var(--gi-tint-green-text);">⭐⭐⭐⭐⭐ Over 4/5</strong><div style="margin:0.5rem 0;font-size:0.875rem;color:var(--gi-tint-green-text);font-weight:700;">🏆 &quot;Top Distributor&quot; Status</div><p style="margin:0;font-size:0.875rem;">Your audiences are displayed in <strong>priority</strong>. You receive the most qualified and highest-paying campaigns first.</p></div></div><h2 id="the-7-evaluation-criteria" tabindex="-1">The 7 evaluation criteria <a class="header-anchor" href="#the-7-evaluation-criteria" aria-label="Permalink to &quot;The 7 evaluation criteria&quot;">​</a></h2><p>Your score is calculated on 7 dimensions. Here is how to optimize them:</p><table tabindex="0"><thead><tr><th>Criterion</th><th>Description</th><th>How to improve</th></tr></thead><tbody><tr><td><strong>1. Pricing</strong></td><td>Consistency of your CPMs compared to your sector&#39;s average</td><td>Regularly compare yourself to similar distributors</td></tr><tr><td><strong>2. Weekly Volume (Reach)</strong></td><td>Stability and size of your distribution capacity</td><td>Maintain a steady volume, avoid sharp peaks/valleys</td></tr><tr><td><strong>3. Brand Attractiveness</strong></td><td>Awareness and image of your brand in its market</td><td>Work on your brand image and complete your profile</td></tr><tr><td><strong>4. Inventory Reliability</strong></td><td>Strict adherence to promised insertion volumes</td><td>Do not over-commit — better to promise less and deliver</td></tr><tr><td><strong>5. Audience Responsiveness</strong></td><td>Real performance (scan rates, conversions)</td><td>Target your campaigns well according to your real audience</td></tr><tr><td><strong>6. Campaign History</strong></td><td>Number of successful campaigns via the platform</td><td>Loyalty is rewarded — continue to operate regularly</td></tr><tr><td><strong>7. Communication &amp; Reporting</strong></td><td>Responsiveness to requests and punctuality of declarations</td><td>Declare your volumes every Mon/Tue, reply within 48h</td></tr></tbody></table><h2 id="the-4-actions-that-boost-the-score" tabindex="-1">The 4 actions that boost the score <a class="header-anchor" href="#the-4-actions-that-boost-the-score" aria-label="Permalink to &quot;The 4 actions that boost the score&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card" style="border-color:var(--vp-c-brand-1);"><strong>⏱️ Respond in under 48h</strong><p style="margin:0.5rem 0 0;font-size:0.875rem;">Accept or decline proposals quickly. Avoid systematic refusals without proposing an alternative.</p></div><div class="gi-value-card" style="border-color:var(--vp-c-brand-1);"><strong>📊 Respect committed volumes</strong><p style="margin:0.5rem 0 0;font-size:0.875rem;">Distribute exactly the promised volume. Provide your reporting on time (Monday/Tuesday).</p></div><div class="gi-value-card" style="border-color:var(--vp-c-brand-1);"><strong>💶 Maintain consistent pricing</strong><p style="margin:0.5rem 0 0;font-size:0.875rem;">Check that your CPMs remain competitive and within your sector&#39;s range.</p></div><div class="gi-value-card" style="border-color:var(--vp-c-brand-1);"><strong>🎯 Optimize audience engagement</strong><p style="margin:0.5rem 0 0;font-size:0.875rem;">Accept campaigns that truly match your audience — scan/click rates impact the score.</p></div></div><h2 id="where-to-find-your-score" tabindex="-1">Where to find your score? <a class="header-anchor" href="#where-to-find-your-score" aria-label="Permalink to &quot;Where to find your score?&quot;">​</a></h2><p>Your score is visible in your distributor portal:</p><p><strong>My Account → Distributor Profile → Score &amp; Reputation</strong></p><p>There you will find:</p><ul><li>Your current rating out of 5</li><li>A detailed breakdown by criterion</li><li>Recommended actions to progress</li></ul><h2 id="frequently-asked-questions" tabindex="-1">Frequently asked questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently asked questions&quot;">​</a></h2><p><strong>My score dropped for no apparent reason — why?</strong> The score is recalculated dynamically. A drop may indicate: a late volume declaration, a campaign with poor performance, or a CPM that has moved out of the market range. See the criterion-by-criterion detail in your profile.</p><p><strong>Can a bad score make me lose already accepted campaigns?</strong> No. Already accepted and ongoing campaigns are not affected. The score only impacts <em>future</em> proposals that you will receive.</p><p><strong>Is the score visible to advertisers?</strong> Yes. Advertisers see your rating and the &quot;Top Distributor&quot; badge if applicable. This is a trust signal that makes selection easier.</p><hr><p><strong>Next step:</strong> Manage your <a href="/handbook/en/publishers/audience-setup.html">audiences and data</a> to attract the most relevant campaigns.</p>',24)])])}const m=t(a,[["render",s]]);export{g as __pageData,m as default};
